        GameObject.FindWithTag("vase").GetComponent<Collectable>().enabled = false;
        GameObject.FindWithTag("vase").GetComponent<Usable>().enabled = false;
        GameObject.FindWithTag("vase").GetComponent<Collider>().enabled = false;
	}
}

